import { useState } from "react";
import { useNavigate, Link, useLocation } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { authService, API } from "@/App";
import axios from "axios";

import {
  GraduationCap,
  Building2,
  BookOpen,
  CreditCard,
  Users,
  FileText,
  ArrowLeft,
  Eye,
  EyeOff,
} from "lucide-react";

const roles = [
  { key: "school_admin", label: "School Admin", desc: "Full school management access", icon: Building2 },
  { key: "teacher", label: "Teacher", desc: "Academics, attendance & results", icon: BookOpen },
  { key: "finance", label: "Finance / Accounts", desc: "Fee collection & financial records", icon: CreditCard },
  { key: "secretary", label: "Secretary", desc: "Student records & announcements", icon: FileText },
  { key: "student", label: "Student / Parent", desc: "View records, fees & results", icon: Users },
];

const LoginPage = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [selectedRole, setSelectedRole] = useState(location.state?.role || null);

  const [formData, setFormData] = useState({
    email: "",
    password: "",
  });

  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const updateField = (field, value) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!selectedRole) {
      toast.error("Please select a role");
      return;
    }

    setLoading(true);

    try {
      const response = await axios.post(`${API}/auth/login`, {
        email: formData.email,
        password: formData.password,
        role: selectedRole,
      });

      const token = response?.data?.access_token || response?.data?.token;

      const user = response?.data?.user;

      if (!token) {
        toast.error("Invalid login response from server");
        return;
      }

      // 🔴 FIX: ensure role is ALWAYS stored
      const safeUser = {
        ...user,
        role: user?.role || selectedRole,
      };

      authService.setAuth(token, safeUser);

      toast.success("Login successful!");

      // 🔴 FIX: role-based redirect
      switch (safeUser.role) {
        case "school_admin":
          navigate("/app/dashboard");
          break;

        case "student":
          navigate("/app/student-portal");
          break;

        case "teacher":
          navigate("/app/teacher-portal");
          break;

        case "finance":
          navigate("/app/finance-portal");
          break;

        case "secretary":
          navigate("/app/secretary-portal");
          break;

        default:
          navigate("/app/dashboard");
      }
    } catch (error) {
      console.error(error);

      toast.error(
        error?.response?.data?.detail || "Invalid email or password"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0B1120] flex items-center justify-center p-6">
      <div className="w-full max-w-md">

        <div className="text-center mb-8">
          <div className="mx-auto w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center mb-4">
            <GraduationCap className="w-10 h-10 text-white" />
          </div>

          <h1 className="text-3xl font-bold text-white">
            Smart-M Hub
          </h1>

          <p className="text-slate-400 mt-2">
            {selectedRole
              ? `Logging in as ${roles.find((r) => r.key === selectedRole)?.label}`
              : "Select how you want to sign in"}
          </p>
        </div>

        {!selectedRole ? (
          <div className="space-y-3">
            {roles.map((role) => {
              const Icon = role.icon;

              return (
                <button
                  key={role.key}
                  onClick={() => setSelectedRole(role.key)}
                  className="w-full flex items-center gap-4 p-4 rounded-xl bg-[#1A2332] border border-[#1E3A4F]/40"
                >
                  <div className="w-10 h-10 flex items-center justify-center">
                    <Icon className="w-5 h-5 text-emerald-400" />
                  </div>

                  <div className="text-left">
                    <p className="text-white font-medium">{role.label}</p>
                    <p className="text-slate-500 text-sm">{role.desc}</p>
                  </div>
                </button>
              );
            })}
          </div>
        ) : (
          <div className="bg-[#1A2332] border border-[#1E3A4F]/40 rounded-2xl p-8">

            <form onSubmit={handleSubmit} className="space-y-5">

              <div>
                <Label className="text-slate-300">Email</Label>
                <Input
                  type="email"
                  value={formData.email}
                  onChange={(e) => updateField("email", e.target.value)}
                  required
                />
              </div>

              <div>
                <Label className="text-slate-300">Password</Label>

                <Input
                  type={showPassword ? "text" : "password"}
                  value={formData.password}
                  onChange={(e) => updateField("password", e.target.value)}
                  required
                />
              </div>

              <Button type="submit" disabled={loading} className="w-full">
                {loading ? "Signing in..." : "Sign In"}
              </Button>
            </form>

            <div className="mt-4 text-center">
              <button onClick={() => setSelectedRole(null)}>
                <ArrowLeft className="w-3 h-3 inline" /> Back
              </button>
            </div>

          </div>
        )}
      </div>
    </div>
  );
};

export default LoginPage;
